import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Obsidian: Save Plans | plannotator","description":"学习配置 Obsidian 集成自动保存计划。一键保存到库，生成标签和元数据。","frontmatter":{"title":"Obsidian: Save Plans | plannotator","sidebarTitle":"Obsidian","subtitle":"Obsidian: Auto-save Plans to Vault","description":"学习配置 Obsidian 集成自动保存计划。一键保存到库，生成标签和元数据。","tags":["plannotator","integration","obsidian","advanced"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"backnotprop/plannotator/advanced/obsidian-integration/index.md","filePath":"backnotprop/plannotator/advanced/obsidian-integration/index.md"}'),i={name:"backnotprop/plannotator/advanced/obsidian-integration/index.md"};function r(s,t,l,d,c,p){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="obsidian-integration-auto-save-plans-to-vault" tabindex="-1">Obsidian Integration: Auto-save Plans to Vault <a class="header-anchor" href="#obsidian-integration-auto-save-plans-to-vault" aria-label="Permalink to &quot;Obsidian Integration: Auto-save Plans to Vault&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Automatically save approved or rejected plans to your Obsidian vault</li><li>Understand frontmatter and tag generation mechanisms</li><li>Customize save paths and folders</li><li>Use backlinks to build knowledge graphs</li></ul><h2 id="the-problem" tabindex="-1">The Problem <a class="header-anchor" href="#the-problem" aria-label="Permalink to &quot;The Problem&quot;">​</a></h2><p>You review AI-generated plans in Plannotator, but after approval, these plans just &quot;disappear.&quot; You want to save these valuable plans to Obsidian for future reference and lookup, but manual copy-pasting is tedious and breaks formatting.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li>You use Obsidian as your knowledge management tool</li><li>You want to preserve and review AI-generated implementation plans long-term</li><li>You want to leverage Obsidian&#39;s graph view and tag system to organize plans</li></ul><h2 id="core-concepts" tabindex="-1">Core Concepts <a class="header-anchor" href="#core-concepts" aria-label="Permalink to &quot;Core Concepts&quot;">​</a></h2><p>Plannotator&#39;s Obsidian integration automatically saves plan content to your Obsidian vault when you approve or reject a plan. The system will:</p><ol><li><strong>Detect vaults</strong>: Automatically read all vaults from Obsidian configuration file</li><li><strong>Generate frontmatter</strong>: Include creation time, source, and tags</li><li><strong>Extract tags</strong>: Automatically extract tags from plan titles and code block languages</li><li><strong>Add backlink</strong>: Insert <code>[[Plannotator Plans]]</code> link to build knowledge graph</li></ol><div class="info custom-block"><p class="custom-block-title">What is Obsidian?</p><p>Obsidian is a local-first bi-directional linking note-taking app that supports Markdown format and visualizes note relationships through graph view.</p></div><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><p>Ensure Obsidian is installed and configured. Plannotator will automatically detect vaults on your system, but you need at least one vault to use this feature.</p><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-open-settings-panel" tabindex="-1">Step 1: Open Settings Panel <a class="header-anchor" href="#step-1-open-settings-panel" aria-label="Permalink to &quot;Step 1: Open Settings Panel&quot;">​</a></h3><p>In the Plannotator interface, click the gear icon in the top-right corner to open the settings panel.</p><p>You should see a settings dialog with multiple configuration options.</p><h3 id="step-2-enable-obsidian-integration" tabindex="-1">Step 2: Enable Obsidian Integration <a class="header-anchor" href="#step-2-enable-obsidian-integration" aria-label="Permalink to &quot;Step 2: Enable Obsidian Integration&quot;">​</a></h3><p>In the settings panel, find the &quot;Obsidian Integration&quot; section and toggle it on.</p><p>After enabling, Plannotator will automatically detect Obsidian vaults on your system.</p><p>You should see a dropdown menu listing detected vaults (e.g., <code>My Vault</code>, <code>Work Notes</code>).</p><h3 id="step-3-select-vault-and-folder" tabindex="-1">Step 3: Select Vault and Folder <a class="header-anchor" href="#step-3-select-vault-and-folder" aria-label="Permalink to &quot;Step 3: Select Vault and Folder&quot;">​</a></h3><p>From the dropdown menu, select the vault where you want to save plans. If no vaults are detected, you can:</p><ol><li>Select the &quot;Custom path...&quot; option</li><li>Enter the full path to your vault in the text box</li></ol><p>Then set the folder name for saving plans in the &quot;Folder&quot; field (default is <code>plannotator</code>).</p><p>You should see a preview path below showing where plans will be saved.</p><h3 id="step-4-approve-or-reject-plan" tabindex="-1">Step 4: Approve or Reject Plan <a class="header-anchor" href="#step-4-approve-or-reject-plan" aria-label="Permalink to &quot;Step 4: Approve or Reject Plan&quot;">​</a></h3><p>After configuration, review AI-generated plans as usual. When you click &quot;Approve&quot; or &quot;Send Feedback,&quot; the plan will be automatically saved to the configured vault.</p><p>You should see a new file created in Obsidian, with filename format like <code>Title - Jan 2, 2026 2-30pm.md</code>.</p><h3 id="step-5-view-saved-file" tabindex="-1">Step 5: View Saved File <a class="header-anchor" href="#step-5-view-saved-file" aria-label="Permalink to &quot;Step 5: View Saved File&quot;">​</a></h3><p>Open the saved file in Obsidian, and you&#39;ll see the following content:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">created</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2026-01-24T14:30:00.000Z</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">source</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plannotator</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">tags</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">plan</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">authentication</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">typescript</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">sql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[Plannotator Plans]]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Implementation Plan: User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">...</span></span></code></pre></div><p>You should notice the YAML frontmatter at the top of the file, containing creation time, source, and tags.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>[ ] Obsidian Integration is enabled in settings panel</li><li>[ ] Vault is selected (or custom path entered)</li><li>[ ] Folder name is set</li><li>[ ] New files appear in Obsidian after approving or rejecting plans</li><li>[ ] Files contain frontmatter and <code>[[Plannotator Plans]]</code> backlink</li></ul><h2 id="frontmatter-and-tags-explained" tabindex="-1">Frontmatter and Tags Explained <a class="header-anchor" href="#frontmatter-and-tags-explained" aria-label="Permalink to &quot;Frontmatter and Tags Explained&quot;">​</a></h2><h3 id="frontmatter-structure" tabindex="-1">Frontmatter Structure <a class="header-anchor" href="#frontmatter-structure" aria-label="Permalink to &quot;Frontmatter Structure&quot;">​</a></h3><p>Each saved plan includes the following frontmatter fields:</p><table tabindex="0"><thead><tr><th>Field</th><th>Example</th><th>Description</th></tr></thead><tbody><tr><td><code>created</code></td><td><code>2026-01-24T14:30:00.000Z</code></td><td>ISO 8601 formatted creation timestamp</td></tr><tr><td><code>source</code></td><td><code>plannotator</code></td><td>Fixed value, identifies source</td></tr><tr><td><code>tags</code></td><td><code>[plan, authentication, typescript]</code></td><td>Automatically extracted tag array</td></tr></tbody></table><h3 id="tag-generation-rules" tabindex="-1">Tag Generation Rules <a class="header-anchor" href="#tag-generation-rules" aria-label="Permalink to &quot;Tag Generation Rules&quot;">​</a></h3><p>Plannotator uses the following rules to automatically extract tags:</p><ol><li><strong>Default tag</strong>: Always includes <code>plannotator</code> tag</li><li><strong>Project name tag</strong>: Automatically extracted from git repository name or directory name</li><li><strong>Title keywords</strong>: Extracts meaningful words from the first H1 heading (excluding common stopwords)</li><li><strong>Code language tag</strong>: Extracts from code block language identifiers (e.g., <code>typescript</code>, <code>sql</code>). Generic configuration languages (like <code>json</code>, <code>yaml</code>, <code>markdown</code>) are automatically filtered.</li></ol><p>Stopwords list (not used as tags):</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p>Tag count limit: Maximum 7 tags, ordered by extraction sequence.</p><h3 id="filename-format" tabindex="-1">Filename Format <a class="header-anchor" href="#filename-format" aria-label="Permalink to &quot;Filename Format&quot;">​</a></h3><p>Filenames use a highly readable format: <code>Title - Jan 2, 2026 2-30pm.md</code></p><table tabindex="0"><thead><tr><th>Part</th><th>Example</th><th>Description</th></tr></thead><tbody><tr><td>Title</td><td><code>User Authentication</code></td><td>Extracted from H1, limited to 50 characters</td></tr><tr><td>Date</td><td><code>Jan 2, 2026</code></td><td>Current date</td></tr><tr><td>Time</td><td><code>2-30pm</code></td><td>Current time (12-hour format)</td></tr></tbody></table><h3 id="backlink-mechanism" tabindex="-1">Backlink Mechanism <a class="header-anchor" href="#backlink-mechanism" aria-label="Permalink to &quot;Backlink Mechanism&quot;">​</a></h3><p>Each plan file has a <code>[[Plannotator Plans]]</code> link inserted at the bottom. This backlink serves to:</p><ul><li><strong>Knowledge graph connection</strong>: In Obsidian&#39;s graph view, all plans connect to the same node</li><li><strong>Quick navigation</strong>: Click <code>[[Plannotator Plans]]</code> to create an index page that summarizes all saved plans</li><li><strong>Bi-directional linking</strong>: Use backlinks in the index page to view all plans</li></ul><h2 id="cross-platform-support" tabindex="-1">Cross-Platform Support <a class="header-anchor" href="#cross-platform-support" aria-label="Permalink to &quot;Cross-Platform Support&quot;">​</a></h2><p>Plannotator automatically detects Obsidian configuration file locations across different operating systems:</p><table tabindex="0"><thead><tr><th>Operating System</th><th>Configuration File Path</th></tr></thead><tbody><tr><td>macOS</td><td><code>~/Library/Application Support/obsidian/obsidian.json</code></td></tr><tr><td>Windows</td><td><code>%APPDATA%\\obsidian/obsidian.json</code></td></tr><tr><td>Linux</td><td><code>~/.config/obsidian/obsidian.json</code></td></tr></tbody></table><p>If automatic detection fails, you can manually enter the vault path.</p><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="problem-1-vaults-not-detected" tabindex="-1">Problem 1: Vaults Not Detected <a class="header-anchor" href="#problem-1-vaults-not-detected" aria-label="Permalink to &quot;Problem 1: Vaults Not Detected&quot;">​</a></h3><p><strong>Symptom</strong>: Dropdown menu shows &quot;Detecting...&quot; but no results</p><p><strong>Cause</strong>: Obsidian configuration file doesn&#39;t exist or is malformed</p><p><strong>Solution</strong>:</p><ol><li>Confirm Obsidian is installed and has been opened at least once</li><li>Check if configuration file exists (refer to paths in table above)</li><li>Use &quot;Custom path...&quot; to manually enter vault path</li></ol><h3 id="problem-2-cannot-find-saved-file" tabindex="-1">Problem 2: Cannot Find Saved File <a class="header-anchor" href="#problem-2-cannot-find-saved-file" aria-label="Permalink to &quot;Problem 2: Cannot Find Saved File&quot;">​</a></h3><p><strong>Symptom</strong>: After approving a plan, no new files appear in Obsidian</p><p><strong>Cause</strong>: Vault path is incorrect or Obsidian hasn&#39;t refreshed</p><p><strong>Solution</strong>:</p><ol><li>Check if the preview path in settings panel is correct</li><li>In Obsidian, click &quot;Reload vault&quot; or press <code>Cmd+R</code> (macOS) / <code>Ctrl+R</code> (Windows/Linux)</li><li>Verify the correct vault is selected</li></ol><h3 id="problem-3-filename-contains-special-characters" tabindex="-1">Problem 3: Filename Contains Special Characters <a class="header-anchor" href="#problem-3-filename-contains-special-characters" aria-label="Permalink to &quot;Problem 3: Filename Contains Special Characters&quot;">​</a></h3><p><strong>Symptom</strong>: Underscores or other replacement characters appear in filename</p><p><strong>Cause</strong>: Title contains characters not supported by file system (<code>&lt; &gt; : &quot; / \\ | ? *</code>)</p><p><strong>Solution</strong>: This is expected behavior. Plannotator automatically replaces these characters to avoid file system errors.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Obsidian integration seamlessly connects your plan review workflow with knowledge management:</p><ul><li>✅ Automatically save approved or rejected plans</li><li>✅ Intelligently extract tags for easy retrieval</li><li>✅ Generate frontmatter for consistent metadata format</li><li>✅ Add backlinks to build knowledge graphs</li></ul><p>After configuring once, every review will be automatically archived—no more manual copy-pasting.</p><h2 id="next-up" tabindex="-1">Next Up <a class="header-anchor" href="#next-up" aria-label="Permalink to &quot;Next Up&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../bear-integration/">Bear Integration</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to save plans to Bear note-taking app</li><li>Differences between Bear integration and Obsidian integration</li><li>Using x-callback-url to automatically create notes</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Line Number</th></tr></thead><tbody><tr><td>Detect Obsidian vaults</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L135-L175" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>135-175</td></tr><tr><td>Save plans to Obsidian</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L180-L227" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>180-227</td></tr><tr><td>Extract tags</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Generate frontmatter</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L81-L89" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>81-89</td></tr><tr><td>Generate filename</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L111-L127" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>111-127</td></tr><tr><td>Obsidian settings storage</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/obsidian.ts#L36-L43" target="_blank" rel="noreferrer"><code>packages/ui/utils/obsidian.ts</code></a></td><td>36-43</td></tr><tr><td>Settings UI component</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L387-L491" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>387-491</td></tr></tbody></table><p><strong>Key Functions</strong>:</p><ul><li><code>detectObsidianVaults()</code>: Reads Obsidian configuration file, returns list of available vault paths</li><li><code>saveToObsidian(config)</code>: Saves plan to specified vault, including frontmatter and backlink</li><li><code>extractTags(markdown)</code>: Extracts tags from plan content (title keywords, code languages, project name)</li><li><code>generateFrontmatter(tags)</code>: Generates YAML frontmatter string</li><li><code>generateFilename(markdown)</code>: Generates readable filename</li></ul><p><strong>Business Rules</strong>:</p><ul><li>Maximum 7 tags (L73)</li><li>Filename limited to 50 characters (L102)</li><li>Supports cross-platform config file path detection (L141-149)</li><li>Automatically creates non-existent folders (L208)</li></ul></details>`,79)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
